__kernel void compute_distances_kernel(
    __global const char* sandbox,
    __global float* distances,
    float target_lat,
    float target_long,
    int rec_count,
    int rec_length,
    int latitude_pos
) {
    int i = get_global_id(0);
    if (i < rec_count) {
        int base_pos = i * rec_length + latitude_pos - 1;

        float tmp_lat = 0.0f;
        float sign_lat = 1.0f;
        float decimal_place_lat = 0.0f;
        int found_decimal_lat = 0;

        for (int j = 0; j < 10; j++) {
            char c = sandbox[base_pos + j];
            if (c == '\0' || c == '\n') break;
            if (c == '-') {
                sign_lat = -1.0f;
            } else if (c == '.') {
                found_decimal_lat = 1;
                decimal_place_lat = 1.0f;
            } else if (c >= '0' && c <= '9') {
                float digit = (float)(c - '0');
                if (!found_decimal_lat) {
                    tmp_lat = tmp_lat * 10.0f + digit;
                } else {
                    decimal_place_lat *= 0.1f;
                    tmp_lat += digit * decimal_place_lat;
                }
            }
        }
        tmp_lat *= sign_lat;

        float tmp_long = 0.0f;
        float sign_long = 1.0f;
        float decimal_place_long = 0.0f;
        int found_decimal_long = 0;

        for (int j = 0; j < 10; j++) {
            char c = sandbox[base_pos + 5 + j];
            if (c == '\0' || c == '\n') break;
            if (c == '-') {
                sign_long = -1.0f;
            } else if (c == '.') {
                found_decimal_long = 1;
                decimal_place_long = 1.0f;
            } else if (c >= '0' && c <= '9') {
                float digit = (float)(c - '0');
                if (!found_decimal_long) {
                    tmp_long = tmp_long * 10.0f + digit;
                } else {
                    decimal_place_long *= 0.1f;
                    tmp_long += digit * decimal_place_long;
                }
            }
        }
        tmp_long *= sign_long;

        float lat_diff = tmp_lat - target_lat;
        float long_diff = tmp_long - target_long;
        distances[i] = sqrt(lat_diff * lat_diff + long_diff * long_diff);
    }
}
